package com.nattechnologies.trastcms.plugins.saas; import com.nattechnologies.trastcms.domain.plugin.BundledPluginStateRepository; import com.nattechnologies.trastcms.service.NotFoundException; import org.springframework.stereotype.Component; @Component class SaasPluginGuard{private final BundledPluginStateRepository states;SaasPluginGuard(BundledPluginStateRepository s){states=s;}void requireEnabled(){if(!states.findById("trastsaas").map(x->x.isEnabled()).orElse(false))throw new NotFoundException("TrastSaaS está desactivado");}}
